40	function computeComponentPremium(items: Array<{ type: string }>): number {
41	  const counts = new Map<string, number>();
42	  for (const item of items) {
43	    if (COMPONENT_TYPES.has(item.type)) {
44	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
45	    }
46	  }
47	  let premium = 0;
48	  for (const [type, count] of counts) {
49	    if (count === BLOCK_SIZE) {
50	      premium += BLOCK_PREMIUM;
51	    } else {
52	      premium += count * (BASE_PREMIUMS[type] ?? 0);
53	    }
54	  }
55	  return premium;
56	}
