58	function computeQuotePremium(items: Item[], customer: { yearsWithMHPCO: number }, isFollowUp: boolean): number {
59	  const standardItems = items.filter((item) => !COMPONENT_TYPES.has(item.type));
60	  let policyBase = 0;
61	  let itemSurcharges = 0;
62	  for (const item of standardItems) {
63	    const basePremium = BASE_PREMIUMS[item.type] ?? 0;
64	    policyBase += basePremium;
65	    if (item.cursed) {
66	      itemSurcharges += basePremium * CURSE_SURCHARGE_RATE;
67	    }
68	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
69	      itemSurcharges += basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE;
70	    }
71	  }
72	  const componentPremium = computeComponentPremium(items);
73	  policyBase += componentPremium;
74	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
75	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
76	  const followUpDiscount = isFollowUp ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
77	  return Math.ceil(policyBase + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
78	}
