81	  let quoteCount = 0;
82	  const results = scenario.steps.map((step) => {
83	    if (step.op === "quote") {
84	      const items = step.items ?? [];
85	      const isFollowUp = quoteCount > 0;
86	      quoteCount++;
87	      return { premium: computeQuotePremium(items, scenario.customer, isFollowUp) };
88	    }
89	    return {};
90	  });
91	  return { results };
